mapper.select:
select distinct u.*, r.role_name,r.role_id, r.role_key,r.menu_check_strictly, r.remark
from sys_user u
left join sys_user_role ur on u.user_id = ur.user_id
left join sys_role r on r.role_id = ur.role_id


        AND u.user_id != #{user.userId}


        AND u.username like concat('%', #{user.username}, '%')


        AND u.status = #{user.status}


        AND u.gender = #{user.gender}


        AND u.mobile like concat('%', #{user.mobile}, '%')


        AND u.nickname like concat('%', #{user.nickname}, '%')


        AND u.person_name like concat('%', #{user.personName}, '%')


        AND r.role_id=#{user.roleId}


order by u.user_id desc

select u.* from sys_user u
where 1=1

    AND u.user_id = #{user.userId}


    AND u.username like concat('%', #{user.username}, '%')


    AND u.status = #{user.status}


    AND u.mobile like concat('%', #{user.mobile}, '%')

select count(*)
from sys_user
where mobile = #{mobile}
  and status = 0
  and user_id != #{id}

select * from sys_user



        and mobile=#{mobile}



        and status=#{status}

SELECT DISTINCT
mu.*,st.count
FROM
sys_user t1
LEFT JOIN select_count st ON mu.id = st.user_id AND st.use_id =#{params.loginId}



        AND mu.com_code = #{params.companyCode}



        AND mu.person_name LIKE CONCAT('%', #{params.personName}, '%')



        AND mu.dept_id = #{params.deptId}


order by COALESCE(st.count, 0) DESC
